/**
 * Parity measurement: the remark→Typst emitter against the committed pandoc
 * goldens (fixtures/golden-typst/, regenerated by
 * scripts/update-golden-typst.ts). Runs everywhere — the goldens are
 * committed, so no binaries are needed.
 *
 * Comparison is exact up to line endings (goldens are stored LF; a CRLF
 * checkout must not fail the suite). Current status — including what still
 * diverges on inputs beyond the demo fixture — is documented in
 * ./remark-typst-parity.md.
 */
import { describe, expect, it } from "vitest";
import { readFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { join } from "node:path";
import { NodePlatform } from "../platform/node-platform.ts";
import { loadProject } from "../project/load-project.ts";
import { baseOf, dirOf, stemOf } from "../project/paths.ts";
import { extractMermaidBlocks } from "./mermaid.ts";
import { markdownToTypst } from "./remark-typst.ts";

const root = join(fileURLToPath(new URL(".", import.meta.url)), "../../../..");
const fixtureDir = join(root, "fixtures/demo-report").replaceAll("\\", "/");
const goldenDir = join(root, "fixtures/golden-typst");

const normalizeEol = (s: string) => s.replaceAll("\r\n", "\n");

describe("remark emitter parity with the pandoc goldens", () => {
  it("emits byte-identical Typst for every demo section", async () => {
    const project = await loadProject(new NodePlatform(), fixtureDir);
    expect(project.meta.sections.length).toBeGreaterThan(0);

    for (const section of project.meta.sections) {
      const source = await readFile(join(fixtureDir, section.file), "utf8");
      // Mirror the builder: mermaid blocks never reach the converter.
      const { markdown } = extractMermaidBlocks(source);
      const typst = markdownToTypst(markdown, dirOf(section.file));
      const golden = await readFile(
        join(goldenDir, `${stemOf(baseOf(section.file))}.typ`),
        "utf8",
      );
      expect(normalizeEol(typst), section.file).toBe(normalizeEol(golden));
    }
  });
});
